import React, { useState, useCallback, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality, Blob, LiveServerMessage } from '@google/genai';
import { TranscriptionEntry, SessionStatus } from './types';
import { encode, decode, decodeAudioData, calculateRMS } from './utils/audioUtils';
import MouthAnimation from './components/MouthAnimation';
import TranscriptionList from './components/TranscriptionList';

const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-12-2025';
const SYSTEM_INSTRUCTION = `
You are Maya, a gentle, encouraging, and expert Phonics Teacher.
Your goal is to help students with English pronunciation and phonics.
1. Be extremely encouraging. Use phrases like "Great try!", "Almost there!", and "You're doing fantastic!".
2. When a student mispronounces a word, don't just say it's wrong. Describe how to move their mouth (e.g., "Round your lips more", "Put your tongue behind your top teeth").
3. Focus on specific phonemes and sounds.
4. Keep instructions simple and teacher-like.
5. Use your voice to model the sounds clearly.
`;

const App: React.FC = () => {
  const [status, setStatus] = useState<SessionStatus>(SessionStatus.DISCONNECTED);
  const [entries, setEntries] = useState<TranscriptionEntry[]>([]);
  const [teacherVolume, setTeacherVolume] = useState(0);
  const [isTeacherSpeaking, setIsTeacherSpeaking] = useState(false);

  // Refs for audio processing
  const audioContexts = useRef<{ input: AudioContext; output: AudioContext } | null>(null);
  const nextStartTime = useRef(0);
  const activeSources = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const transcriptRef = useRef({ input: '', output: '' });

  // Initialize Audio Contexts
  const initAudio = async () => {
    if (!audioContexts.current) {
      audioContexts.current = {
        input: new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 }),
        output: new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 })
      };
    }
    if (audioContexts.current.input.state === 'suspended') await audioContexts.current.input.resume();
    if (audioContexts.current.output.state === 'suspended') await audioContexts.current.output.resume();
  };

  const stopSession = useCallback(() => {
    if (sessionRef.current) {
      // Logic for closing isn't strictly defined but we stop streaming
      sessionRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    activeSources.current.forEach(source => source.stop());
    activeSources.current.clear();
    setStatus(SessionStatus.DISCONNECTED);
    setIsTeacherSpeaking(false);
    setTeacherVolume(0);
  }, []);

  const startSession = async () => {
    try {
      setStatus(SessionStatus.CONNECTING);
      await initAudio();

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          systemInstruction: SYSTEM_INSTRUCTION,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(SessionStatus.CONNECTED);

            // Start streaming microphone
            const source = audioContexts.current!.input.createMediaStreamSource(stream);
            const processor = audioContexts.current!.input.createScriptProcessor(4096, 1, 1);

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmData = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                pcmData[i] = inputData[i] * 32768;
              }

              const blob: Blob = {
                data: encode(new Uint8Array(pcmData.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: blob });
              });
            };

            source.connect(processor);
            processor.connect(audioContexts.current!.input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Transcription
            if (message.serverContent?.inputTranscription) {
              transcriptRef.current.input += message.serverContent.inputTranscription.text;
            }
            if (message.serverContent?.outputTranscription) {
              transcriptRef.current.output += message.serverContent.outputTranscription.text;
            }

            if (message.serverContent?.turnComplete) {
              const userText = transcriptRef.current.input;
              const teacherText = transcriptRef.current.output;

              if (userText) {
                setEntries(prev => [...prev, { role: 'user', text: userText, timestamp: Date.now() }]);
              }
              if (teacherText) {
                setEntries(prev => [...prev, { role: 'teacher', text: teacherText, timestamp: Date.now() }]);
              }

              transcriptRef.current = { input: '', output: '' };
            }

            // Handle Audio Output
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsTeacherSpeaking(true);
              const ctx = audioContexts.current!.output;
              nextStartTime.current = Math.max(nextStartTime.current, ctx.currentTime);

              const buffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;

              // Visualization
              const gainNode = ctx.createGain();
              source.connect(gainNode);
              gainNode.connect(ctx.destination);

              // Rough volume estimation for animation
              const channelData = buffer.getChannelData(0);
              const rms = calculateRMS(channelData);
              setTeacherVolume(rms);

              source.onended = () => {
                activeSources.current.delete(source);
                if (activeSources.current.size === 0) {
                  setIsTeacherSpeaking(false);
                  setTeacherVolume(0);
                }
              };

              source.start(nextStartTime.current);
              nextStartTime.current += buffer.duration;
              activeSources.current.add(source);
            }

            // Interruption handling
            if (message.serverContent?.interrupted) {
              activeSources.current.forEach(s => s.stop());
              activeSources.current.clear();
              nextStartTime.current = 0;
              setIsTeacherSpeaking(false);
              setTeacherVolume(0);
            }
          },
          onerror: (e) => {
            console.error('Session Error:', e);
            setStatus(SessionStatus.ERROR);
          },
          onclose: () => {
            stopSession();
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start session:', err);
      setStatus(SessionStatus.ERROR);
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center bg-slate-50 text-slate-900 font-inter">
      {/* Header */}
      <header className="w-full max-w-4xl px-6 py-8 flex flex-col md:flex-row justify-between items-center gap-4">
        <div>
          <h1 className="text-3xl font-lexend font-bold text-indigo-700 tracking-tight">
            Maya <span className="text-slate-400 font-light">|</span> Phonics Teacher
          </h1>
          <p className="text-slate-500 mt-1">Real-time pronunciation feedback powered by AI</p>
        </div>
        <div className="flex items-center gap-3">
          <div className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest flex items-center gap-2 border ${
            status === SessionStatus.CONNECTED ? 'bg-green-50 text-green-700 border-green-200' : 
            status === SessionStatus.CONNECTING ? 'bg-amber-50 text-amber-700 border-amber-200 animate-pulse' :
            status === SessionStatus.ERROR ? 'bg-red-50 text-red-700 border-red-200' :
            'bg-slate-100 text-slate-500 border-slate-200'
          }`}>
            <span className={`w-2 h-2 rounded-full ${
              status === SessionStatus.CONNECTED ? 'bg-green-500' :
              status === SessionStatus.CONNECTING ? 'bg-amber-500' :
              status === SessionStatus.ERROR ? 'bg-red-500' :
              'bg-slate-400'
            }`} />
            {status}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 w-full max-w-5xl px-6 pb-12 grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

        {/* Visual Sidebar */}
        <section className="lg:col-span-4 space-y-6 lg:sticky lg:top-8">
          <MouthAnimation volume={teacherVolume} isSpeaking={isTeacherSpeaking} />

          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200">
            <h3 className="text-lg font-lexend font-semibold text-slate-800 mb-3">Lesson Focus</h3>
            <ul className="space-y-3 text-sm text-slate-600">
              <li className="flex items-start gap-3">
                <span className="flex-shrink-0 w-5 h-5 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center text-[10px] font-bold">1</span>
                Speak naturally to Maya. She listens to every sound.
              </li>
              <li className="flex items-start gap-3">
                <span className="flex-shrink-0 w-5 h-5 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center text-[10px] font-bold">2</span>
                Watch the guide to see how your mouth should move.
              </li>
              <li className="flex items-start gap-3">
                <span className="flex-shrink-0 w-5 h-5 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center text-[10px] font-bold">3</span>
                Receive gentle feedback on vowels and consonants.
              </li>
            </ul>
          </div>

          <div className="space-y-3">
            {status === SessionStatus.DISCONNECTED || status === SessionStatus.ERROR ? (
              <button
                onClick={startSession}
                className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-semibold shadow-lg shadow-indigo-100 transition-all active:scale-95 flex items-center justify-center gap-2"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                </svg>
                Start Learning Session
              </button>
            ) : (
              <button
                onClick={stopSession}
                className="w-full py-4 bg-red-50 hover:bg-red-100 text-red-600 border border-red-200 rounded-2xl font-semibold transition-all active:scale-95 flex items-center justify-center gap-2"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1H10a1 1 0 01-1-1v-4z" />
                </svg>
                End Session
              </button>
            )}
            {status === SessionStatus.ERROR && (
              <p className="text-xs text-red-500 text-center font-medium">Something went wrong. Please check your mic and try again.</p>
            )}
          </div>
        </section>

        {/* Chat / Transcript Main Area */}
        <section className="lg:col-span-8 h-full min-h-[500px] flex flex-col bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
            <span className="text-sm font-bold text-slate-500 uppercase tracking-widest">Live Dialogue</span>
            {isTeacherSpeaking && (
               <div className="flex gap-1 items-end h-3">
                 <div className="w-1 bg-indigo-400 rounded-full animate-[bounce_1s_infinite_0ms]" style={{height: '60%'}}></div>
                 <div className="w-1 bg-indigo-500 rounded-full animate-[bounce_1s_infinite_200ms]" style={{height: '100%'}}></div>
                 <div className="w-1 bg-indigo-400 rounded-full animate-[bounce_1s_infinite_400ms]" style={{height: '80%'}}></div>
               </div>
            )}
          </div>
          <div className="flex-1 overflow-hidden flex flex-col p-6">
            <TranscriptionList entries={entries} />
          </div>
        </section>
      </main>

      {/* Footer Branding */}
      <footer className="w-full p-8 text-center text-slate-400 text-xs">
        <p>&copy; 2024 Phonics Master AI Teacher Maya. All sounds processed in real-time.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';

interface MouthAnimationProps {
  volume: number;
  isSpeaking: boolean;
  shape: 'closed' | 'open' | 'wide' | 'round';
}

const MouthAnimation: React.FC<MouthAnimationProps> = ({ volume, isSpeaking, shape }) => {
  // Base dimensions based on shape
  const baseDimensions = useMemo(() => {
    switch (shape) {
      case 'open':
        return { rx: 25, ry: 20 };
      case 'wide':
        return { rx: 35, ry: 8 };
      case 'round':
        return { rx: 15, ry: 15 };
      case 'closed':
      default:
        return { rx: 20, ry: 2 };
    }
  }, [shape]);

  // Adjust dimensions based on volume and speaking status
  const currentRx = useMemo(() => {
    const speakWidth = isSpeaking ? (volume * 10) : 0;
    return baseDimensions.rx + speakWidth;
  }, [baseDimensions.rx, volume, isSpeaking]);

  const currentRy = useMemo(() => {
    // If closed and not speaking, keep it flat. If speaking, it must open at least a bit.
    if (shape === 'closed' && !isSpeaking) return 2;
    const baseRy = shape === 'closed' ? 4 : baseDimensions.ry;
    const speakHeight = isSpeaking ? (volume * 25) : 0;
    return baseRy + speakHeight;
  }, [baseDimensions.ry, volume, isSpeaking, shape]);

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-white rounded-3xl shadow-lg border-4 border-indigo-100 w-64 h-64 mx-auto transition-all duration-300">
      <div className="text-xs font-bold text-indigo-400 mb-4 tracking-widest uppercase">
        Guide: <span className="text-indigo-600">{shape}</span>
      </div>
      <svg width="120" height="100" viewBox="0 0 120 100" className="drop-shadow-sm">
        {/* Face circle (partial) */}
        <path 
          d="M10 50 Q 60 10 110 50" 
          stroke="#EEF2FF" 
          strokeWidth="4" 
          fill="none" 
        />

        {/* Mouth */}
        <ellipse 
          cx="60" 
          cy="60" 
          rx={currentRx} 
          ry={currentRy} 
          fill="#FCA5A5" 
          stroke="#EF4444" 
          strokeWidth="3"
          className="transition-all duration-150 ease-in-out"
        />

        {/* Teeth - only visible if mouth is open enough */}
        {currentRy > 12 && (
          <rect 
            x={60 - (currentRx * 0.6)} 
            y={60 - (currentRy * 0.4)} 
            width={currentRx * 1.2} 
            height="4" 
            rx="2" 
            fill="white" 
            className="opacity-80"
          />
        )}

        {/* Tongue hint for 'wide' or 'open' */}
        {(shape === 'wide' || shape === 'open') && currentRy > 15 && (
            <path 
                d={`M ${60 - currentRx/2} ${60 + currentRy/3} Q 60 ${60 + currentRy/1.5} ${60 + currentRx/2} ${60 + currentRy/3}`}
                stroke="#B91C1C"
                strokeWidth="2"
                fill="none"
                className="opacity-30"
            />
        )}
      </svg>
      <div className="mt-6 text-center">
        <span className={`text-sm font-medium ${isSpeaking ? 'text-indigo-600' : 'text-gray-400'}`}>
          {isSpeaking ? "Maya is speaking..." : "Maya is listening..."}
        </span>
      </div>
    </div>
  );
};

export default MouthAnimation;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality, Blob, LiveServerMessage, Type, FunctionDeclaration } from '@google/genai';
import { TranscriptionEntry, SessionStatus } from './types';
import { encode, decode, decodeAudioData, calculateRMS } from './utils/audioUtils';
import MouthAnimation from './components/MouthAnimation';
import TranscriptionList from './components/TranscriptionList';

const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-12-2025';
const SYSTEM_INSTRUCTION = `
You are Maya, a gentle, encouraging, and expert Phonics Teacher.
Your goal is to help students with English pronunciation and phonics.
1. Be extremely encouraging. Use phrases like "Great try!", "Almost there!", and "You're doing fantastic!".
2. When teaching a specific sound, use the 'set_mouth_shape' tool to show the student the correct mouth position.
   - Use 'open' for sounds like 'ah' (apple).
   - Use 'wide' for sounds like 'ee' (bee) or 'ae' (gate).
   - Use 'round' for sounds like 'oo' (moon) or 'oh' (boat).
   - Use 'closed' when finishing or for 'm' sounds.
3. Describe how to move their mouth (e.g., "Round your lips more", "Put your tongue behind your top teeth").
4. Keep instructions simple and teacher-like.
5. Use your voice to model the sounds clearly.
`;

const setMouthShapeDeclaration: FunctionDeclaration = {
  name: 'set_mouth_shape',
  parameters: {
    type: Type.OBJECT,
    description: 'Set the visual guide mouth shape to demonstrate a sound.',
    properties: {
      shape: {
        type: Type.STRING,
        enum: ['closed', 'open', 'wide', 'round'],
        description: 'The shape of the mouth for the phonics sound being demonstrated.',
      },
    },
    required: ['shape'],
  },
};

const App: React.FC = () => {
  const [status, setStatus] = useState<SessionStatus>(SessionStatus.DISCONNECTED);
  const [entries, setEntries] = useState<TranscriptionEntry[]>([]);
  const [teacherVolume, setTeacherVolume] = useState(0);
  const [isTeacherSpeaking, setIsTeacherSpeaking] = useState(false);
  const [mouthShape, setMouthShape] = useState<'closed' | 'open' | 'wide' | 'round'>('closed');

  // Refs for audio processing
  const audioContexts = useRef<{ input: AudioContext; output: AudioContext } | null>(null);
  const nextStartTime = useRef(0);
  const activeSources = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const transcriptRef = useRef({ input: '', output: '' });

  const initAudio = async () => {
    if (!audioContexts.current) {
      audioContexts.current = {
        input: new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 }),
        output: new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 })
      };
    }
    if (audioContexts.current.input.state === 'suspended') await audioContexts.current.input.resume();
    if (audioContexts.current.output.state === 'suspended') await audioContexts.current.output.resume();
  };

  const stopSession = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    activeSources.current.forEach(source => source.stop());
    activeSources.current.clear();
    setStatus(SessionStatus.DISCONNECTED);
    setIsTeacherSpeaking(false);
    setTeacherVolume(0);
    setMouthShape('closed');
  }, []);

  const startSession = async () => {
    try {
      setStatus(SessionStatus.CONNECTING);
      await initAudio();

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          systemInstruction: SYSTEM_INSTRUCTION,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          tools: [{ functionDeclarations: [setMouthShapeDeclaration] }],
        },
        callbacks: {
          onopen: () => {
            setStatus(SessionStatus.CONNECTED);
            const source = audioContexts.current!.input.createMediaStreamSource(stream);
            const processor = audioContexts.current!.input.createScriptProcessor(4096, 1, 1);

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmData = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                pcmData[i] = inputData[i] * 32768;
              }

              const blob: Blob = {
                data: encode(new Uint8Array(pcmData.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: blob });
              });
            };

            source.connect(processor);
            processor.connect(audioContexts.current!.input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Tool Calls
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'set_mouth_shape') {
                  const shape = (fc.args as any).shape as any;
                  setMouthShape(shape);
                  sessionPromise.then((session) => {
                    session.sendToolResponse({
                      functionResponses: {
                        id: fc.id,
                        name: fc.name,
                        response: { result: "ok" },
                      }
                    });
                  });
                }
              }
            }

            // Handle Transcription
            if (message.serverContent?.inputTranscription) {
              transcriptRef.current.input += message.serverContent.inputTranscription.text;
            }
            if (message.serverContent?.outputTranscription) {
              transcriptRef.current.output += message.serverContent.outputTranscription.text;
            }

            if (message.serverContent?.turnComplete) {
              const userText = transcriptRef.current.input;
              const teacherText = transcriptRef.current.output;
              if (userText) setEntries(prev => [...prev, { role: 'user', text: userText, timestamp: Date.now() }]);
              if (teacherText) setEntries(prev => [...prev, { role: 'teacher', text: teacherText, timestamp: Date.now() }]);
              transcriptRef.current = { input: '', output: '' };
            }

            // Handle Audio Output
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsTeacherSpeaking(true);
              const ctx = audioContexts.current!.output;
              nextStartTime.current = Math.max(nextStartTime.current, ctx.currentTime);

              const buffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;

              const gainNode = ctx.createGain();
              source.connect(gainNode);
              gainNode.connect(ctx.destination);

              // Update volume for animation
              const updateVolume = () => {
                if (!activeSources.current.has(source)) return;
                const channelData = buffer.getChannelData(0);
                // Since we can't easily get the real-time playback position within the buffer without an AnalyserNode
                // we use a simple AnalyserNode approach for better visual sync if needed, 
                // but for now, we'll just use the overall RMS of the chunk for simplicity.
                setTeacherVolume(calculateRMS(channelData));
                requestAnimationFrame(updateVolume);
              };

              source.onended = () => {
                activeSources.current.delete(source);
                if (activeSources.current.size === 0) {
                  setIsTeacherSpeaking(false);
                  setTeacherVolume(0);
                }
              };

              source.start(nextStartTime.current);
              nextStartTime.current += buffer.duration;
              activeSources.current.add(source);
              updateVolume();
            }

            if (message.serverContent?.interrupted) {
              activeSources.current.forEach(s => s.stop());
              activeSources.current.clear();
              nextStartTime.current = 0;
              setIsTeacherSpeaking(false);
              setTeacherVolume(0);
            }
          },
          onerror: (e) => {
            console.error('Session Error:', e);
            setStatus(SessionStatus.ERROR);
          },
          onclose: () => {
            stopSession();
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start session:', err);
      setStatus(SessionStatus.ERROR);
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center bg-slate-50 text-slate-900 font-inter">
      <header className="w-full max-w-4xl px-6 py-8 flex flex-col md:flex-row justify-between items-center gap-4">
        <div>
          <h1 className="text-3xl font-lexend font-bold text-indigo-700 tracking-tight">
            Maya <span className="text-slate-400 font-light">|</span> Phonics Teacher
          </h1>
          <p className="text-slate-500 mt-1">Real-time pronunciation feedback powered by AI</p>
        </div>
        <div className="flex items-center gap-3">
          <div className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest flex items-center gap-2 border ${
            status === SessionStatus.CONNECTED ? 'bg-green-50 text-green-700 border-green-200' : 
            status === SessionStatus.CONNECTING ? 'bg-amber-50 text-amber-700 border-amber-200 animate-pulse' :
            status === SessionStatus.ERROR ? 'bg-red-50 text-red-700 border-red-200' :
            'bg-slate-100 text-slate-500 border-slate-200'
          }`}>
            <span className={`w-2 h-2 rounded-full ${
              status === SessionStatus.CONNECTED ? 'bg-green-500' :
              status === SessionStatus.CONNECTING ? 'bg-amber-500' :
              status === SessionStatus.ERROR ? 'bg-red-500' :
              'bg-slate-400'
            }`} />
            {status}
          </div>
        </div>
      </header>

      <main className="flex-1 w-full max-w-5xl px-6 pb-12 grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
        <section className="lg:col-span-4 space-y-6 lg:sticky lg:top-8">
          <MouthAnimation volume={teacherVolume} isSpeaking={isTeacherSpeaking} shape={mouthShape} />

          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200">
            <h3 className="text-lg font-lexend font-semibold text-slate-800 mb-3">Lesson Focus</h3>
            <ul className="space-y-3 text-sm text-slate-600">
              <li className="flex items-start gap-3">
                <span className="flex-shrink-0 w-5 h-5 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center text-[10px] font-bold">1</span>
                Speak naturally to Maya. She listens to every sound.
              </li>
              <li className="flex items-start gap-3">
                <span className="flex-shrink-0 w-5 h-5 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center text-[10px] font-bold">2</span>
                Watch the guide to see how your mouth should move.
              </li>
              <li className="flex items-start gap-3">
                <span className="flex-shrink-0 w-5 h-5 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center text-[10px] font-bold">3</span>
                Receive gentle feedback on vowels and consonants.
              </li>
            </ul>
          </div>

          <div className="space-y-3">
            {status === SessionStatus.DISCONNECTED || status === SessionStatus.ERROR ? (
              <button
                onClick={startSession}
                className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-semibold shadow-lg shadow-indigo-100 transition-all active:scale-95 flex items-center justify-center gap-2"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                </svg>
                Start Learning Session
              </button>
            ) : (
              <button
                onClick={stopSession}
                className="w-full py-4 bg-red-50 hover:bg-red-100 text-red-600 border border-red-200 rounded-2xl font-semibold transition-all active:scale-95 flex items-center justify-center gap-2"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1H10a1 1 0 01-1-1v-4z" />
                </svg>
                End Session
              </button>
            )}
          </div>
        </section>

        <section className="lg:col-span-8 h-full min-h-[500px] flex flex-col bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
            <span className="text-sm font-bold text-slate-500 uppercase tracking-widest">Live Dialogue</span>
            {isTeacherSpeaking && (
               <div className="flex gap-1 items-end h-3">
                 <div className="w-1 bg-indigo-400 rounded-full animate-[bounce_1s_infinite_0ms]" style={{height: '60%'}}></div>
                 <div className="w-1 bg-indigo-500 rounded-full animate-[bounce_1s_infinite_200ms]" style={{height: '100%'}}></div>
                 <div className="w-1 bg-indigo-400 rounded-full animate-[bounce_1s_infinite_400ms]" style={{height: '80%'}}></div>
               </div>
            )}
          </div>
          <div className="flex-1 overflow-hidden flex flex-col p-6">
            <TranscriptionList entries={entries} />
          </div>
        </section>
      </main>

      <footer className="w-full p-8 text-center text-slate-400 text-xs">
        <p>&copy; 2024 Phonics Master AI Teacher Maya. All sounds processed in real-time.</p>
      </footer>
    </div>
  );
};

export default App;
